                      <div className="flex-1 min-w-0">
                        <div className="text-sm font-bold text-white">{m.map_name}</div>
                        <div className="text-[10px] text-slate-500">{m.agent} ┬╖ {m.kills}/{m.deaths}/{m.assists} KDA</div>
