                          </div>
                          <div className="text-[10px] text-slate-500">RR</div>
                        </div>
                      </div>
                    </div>
                  ))}
                </div>
                <Link href="/matches" className="flex items-center justify-center gap-2 text-xs text-[#ff4655] font-bold hover:underline py-2">
                  View all matches <ChevronRight size={13} />
